var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"저, 저질러 버렸다!","JPN":"や、やってしまった！","ENG":"I... I did it!","TWN":"差…差點完蛋！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"지난 코미페 때 분위기에 휘말려 버려서 그만…… 진짜 한다고 해버렸어, 게임 제작!","JPN":"この前のコミフェで、雰囲気に流されてつい……本当にやるって言っちゃったよ、ゲーム制作！","ENG":"I got overwhelmed at Comic Festival... I told them I’ll join the team!","TWN":"上次在動漫展一時鬼迷心竅……結果答應要製作遊戲！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"으으, 어떡하지? 없던 일로 하고 도망칠까?","JPN":"うう、どうしよう？　なかったことにして逃げようか？","ENG":"Ugh, what do I do? Should I just bail?","TWN":"嗚嗚，怎麼辦？當作沒這回事溜之大吉嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L7_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아, 아니야. 여기서 도망치면, 그때 큰 소리쳤던 게 뭐가 돼?","JPN":"いや、ダメだ。ここで逃げたら、あの時大口を叩いておいてみっともないし。","ENG":"N-no. It’s me against my own words if I decide to run away from this.","TWN":"不，不行，逃走的話，我那時候喊那麼大聲不是很糗嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그런데 이상하네? 무슨 비밀기지도 아니고 산기슭에 학교가 있다는 거야?","JPN":"でもおかしいな。秘密基地でもあるまいし、こんな山のふもとに学校なんてあるのかな？","ENG":"But it’s strange that a school would be this high up in the mountains... It's like some sort of secret hideout.","TWN":"不過還真奇怪？又不是什麼秘密基地，怎麼會有學校在山腳下？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"설마 이거 오타쿠를 상대로 하는 신종 낚시 같은 건……","JPN":"まさかこれ、オタク相手の新種の詐欺とかじゃ……","ENG":"Could this really be some kind of prank targeted for otakus only...?","TWN":"難道是針對御宅族的新型詐騙手法……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"응? 잠깐!","JPN":"うん？　あれは！","ENG":"Huh? Wait a minute!","TWN":"嗯？等等！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"지, 진짜 이런 곳에 학교가 있잖아? 그것도 꽤 넓어!","JPN":"ほ、本当にこんなところに学校がある？　しかも結構広い！","ENG":"Th-there really is a school here! And it’s even big!","TWN":"還…還真的有學校喔？而且還這麼寬敞！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOG_NPC_GAMECIRCLE_QM","text":{"KOREA":"헥! 헥헥! 멍! 멍!","JPN":"へッ！　ヘッヘッ！　ワン！　ワン！","ENG":"*Pant!* *Pant!* Woof! Woof!","TWN":"汪汪！汪汪汪！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOG_NPC_GAMECIRCLE_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_ANIMAL_D2"},{"id":"L17_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"엇, 강아지네? 이 학교에서 기르는 개인가?","JPN":"あっ、犬だ。この学校で飼ってる犬なのかな？","ENG":"Oh, a puppy! Do they raise it here?","TWN":"喔，是小狗狗？是校犬嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그래, 그래, 멍멍아 착하지~","JPN":"よしよし、ワンちゃん、いい子だね～","ENG":"There you go, doggy. Good boy!","TWN":"乖乖喔，狗狗乖～"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"켈베로스! 거기 서! 먼저가면 어떡해!","JPN":"ケルベロス！　待ちなさい！　先に行っちゃダメでしょ！","ENG":"Cerberus! Stop right there! You shouldn’t leave me behind!","TWN":"克爾柏洛斯！別跑，怎麼可以自己先跑掉呢！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOG_NPC_GAMECIRCLE_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응? 너는…… 박스 군?","JPN":"あら？　あなたは……ダンボール君？","ENG":"Huh? Aren’t you... Boxie?","TWN":"嗯？你是……紙箱小朋友？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOG_NPC_GAMECIRCLE_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"어라? 누나는 분명히……!?","JPN":"あれ？　お姉さんは確か……！？","ENG":"Huh? And you're...!","TWN":"嗯？姊姊你不是……！？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"여기까지 오기 힘들었을 텐데…… 와 줘서 정말 고마워 박스 군.","JPN":"こんなところまで大変だったよね……来てくれて本当にありがとう、ダンボール君。","ENG":"It would have been quite a ride to get here... Thanks for coming, Boxie.","TWN":"這裡不好找吧……很謝謝你來，紙箱小朋友。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"DOG_NPC_GAMECIRCLE_NULL","text":{"KOREA":"멍! 멍!","JPN":"ワン！　ワン！","ENG":"Woof! Woof!","TWN":"汪汪！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하하, 켈베로스도 박스 군이 반갑대!","JPN":"あは、ケルベロスもダンボール君に会えて嬉しいって！","ENG":"Ha ha, Cerberus says hi to you too!","TWN":"哈哈，克爾柏洛斯也很歡迎你喔！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"헤헷, 아니에요. 약속했으니까요.","JPN":"へへっ、どういたしまして。約束しましたからね。","ENG":"Heh heh, It’s nothing. I made a promise after all.","TWN":"呵呵，沒有啦，畢竟我都已經答應了。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와, 역시 박스 군은 믿음직스럽구나. 뭐 마실래?","JPN":"わあ、やっぱりダンボール君は頼もしいね。何か飲む？","ENG":"Wow, I knew you were responsible. Can I get you anything to drink?","TWN":"哇，你果然很可靠呢，要喝點什麼嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"으음, 저는 어른이니까 블랙으로 주세요. 헤헷.","JPN":"うーん、僕は大人ですからブラックで。へへっ。","ENG":"Mm. Black coffee please, since I’m responsible and mature and all. Heh.","TWN":"嗯嗯，身為一個大人，請給我來一杯美式，呵呵。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아얏!","JPN":"痛っ！","ENG":"Ow!","TWN":"哎喔！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"얼라가 블랙은 뭔 블랙이고? 그냥 오렌지 주스나 무라!","JPN":"ガキのくせに何がブラックや。オレンジジュースでも飲まんかい！","ENG":"Coffee is out of the question! Get yourself some orange juice, kiddo!","TWN":"小朋友喝什麼美式？你給我喝柳橙汁唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"어, 리네야 일찍 왔네?","JPN":"あれ、マリちゃん。早かったね。","ENG":"Oh, Rinae! You’re here early.","TWN":"喔，璃奈，你今天怎麼這麼早？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"어. 평소보다 수업이 조금 일찍 끝났다.","JPN":"せやで。いつもより授業がちょっと早めに終わったからな。","ENG":"Yeah, school ended earlier than usual.","TWN":"嗯，今天課結束得比較早唄。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그러고보니 여긴 무슨 학교에요? 건물이 큰 것치고 학생도 선생님도 별로 없던데…….","JPN":"そういえば、ここは何の学校なんですか？　建物が大きい割には、生徒も先生もあまりいないみたいですけど……","ENG":"What school is this? There aren’t many teachers and students compared to how big it is...","TWN":"不過這裡是什麼學校？校園明明很大，卻沒見到幾位老師和學生……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L49_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아하하, 그게……","JPN":"あはは、それが……","ENG":"Ah ha ha, it’s...","TWN":"哈哈哈，這是……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"쯧쯔, 그라믄 안 돼, 그라믄.","JPN":"ちっちっ、そんなんあかん、そんなん。","ENG":"Tsk tsk, that ain’t right.","TWN":"嘖嘖，不可以這樣唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"꼬맹이가 함부로 어른들의 사정 같은 걸 알려고 하면 안 돼.","JPN":"じゃりんこが大人の事情なんかを知ろうとしちゃあかんで。","ENG":"Kiddo like you shouldn’t be nosy about adult business.","TWN":"小朋友怎麼可以打聽大人的事呢！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그러는 박스 니는 이 시간에 여기 있어도 괘안나? 학교는?","JPN":"そういうダンボール、あんたはこの時間にここにいて大丈夫なんか？　学校は？","ENG":"But how are you here? Ain’t ya supposed to be in school?","TWN":"倒是紙箱你，怎麼會這個時間來？不用去學校嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"흥, 저도 사정이 있다고요. 누나한테는 절대 말 안 할거지만!","JPN":"ふん、僕にも事情があるんです。マリさんには絶対言いませんけど！","ENG":"Hmph, that's my business, thank you very much. And I'm not telling you!","TWN":"哼，我也有我的理由，而且絕對不會跟你說！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L6_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 그새 삐진기가? 박스, 니 보기보다 귀엽네?","JPN":"へへっ、もうすねたん？　ダンボール、あんた思ったよりかわええな。","ENG":"Heh, pouting already? You’re cuter than I thought ya were, Box.","TWN":"嘿嘿，生氣啦？紙箱，你蠻可愛的嘛？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L7_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"삐, 삐지긴 누가 삐졌다는 거예요!","JPN":"す、すねてなんかいません！","ENG":"P-pout?! Who said anything about that?!","TWN":"我…我才沒有咧，你才生氣！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L8_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"빨리 회의나 하자고요! 저희 비즈니스 관계잖아요!","JPN":"それより、早く会議しましょう！　僕たちはビジネス関係なんですから！","ENG":"Let's cut the chitchat and start the meeting already! We’re here to work, no?","TWN":"趕快開會吧！我們只是公事上的關係！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L9_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 알았다, 알았다. 내 쌤이랑 보라 금방 데려올게.","JPN":"へへっ、わかった、わかった。ウチがすぐ先生とシホ連れてくるわ。","ENG":"Heh, alrighty. I’ll go fetch Teach and Bora.","TWN":"嘿嘿，好好好，我找老師和寶拉過來唄。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자, 그럼 지금부터 카운터즈 사가의 기획회의를 시작해볼까요?","JPN":"さて。それじゃあ、これからカウンターズ・サーガの企画会議を始めようか。","ENG":"We will now start the design meeting of Counters Saga.","TWN":"好，那就開始進行制裁者傳奇的企劃會議吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오늘은 우선 첫날이니까 앞으로 제작할 카운터즈 사가의 방향성을 결정해보죠.","JPN":"今日は初日だから、これから制作するカウンターズ・サーガの方向性から決めよう。","ENG":"Since it’s our first day, let's discuss the general direction we should take with Counters Saga.","TWN":"今天是第一天，先決定制裁者傳奇之後的製作方向吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"쌤, 저요! 저요! 제가 먼저 할래요!","JPN":"先生、はい！　はーい！　ウチからいきます！","ENG":"Me, Teach! Me! I wanna go first!","TWN":"老師，我我我！我先說！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래요, 리네 양.","JPN":"どうぞ、マリ君。","ENG":"Very well, Rinae.","TWN":"好，璃奈你先說。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그야, 당연히 주인공, 미리네의 화려하고 멋진 필살기 아니겠어요?","JPN":"そりゃあ、当然主人公マリの派手でカッコいい必殺技じゃないですか？","ENG":"Obviously... We should be focusing on the special move for the protagonist, Mi Rinae!","TWN":"當然是主角宓璃奈華麗又酷炫的必殺技囉，大家說是不是？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L19_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……엥?","JPN":"……ええ？","ENG":"...Huh?","TWN":"……蛤？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"화염, 빙결, 전격 속성의 무기들을 슉슉슉! 쾅! 휘두르면 땅에서 폭발이 콰과과광……!!","JPN":"火炎、氷結、電撃属性の武器をしゅぱーっ！　ドーン！　振り回すと地面から爆発がドドドド……！！","ENG":"Pyro, Cryo and Electro weapons! She swings them around! Wham! The ground breaks, then Boom! Explosions!","TWN":"揮舞火焰、冰凍、閃電屬性的武器，咻咻咻！砰！然後在地上大爆炸……！！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그걸 맞은 보스는 <color=#ffd34c>큭! 과연 대단하군! 하지만 거기까지다!</color> 하면서 새로운 폼으로 변신하면서 2페이즈가 시작되는 거죠!","JPN":"それに当たったボスは<color=#ffd34c>くっ！　さすがだな！　だがそこまでだ！</color>って言って次の形態に変身して、第2フェーズが始まるんですよ！","ENG":"The boss, struck right on the spot goes like <color=#ffd34c>Kggh! Impressive... But this is as far as you will get!</color> and reveals his ultimate form! And BOOM! Phase 2!","TWN":"接著被打到的BOSS嘴上說<color=#ffd34c>呃！果然厲害！不過一切到此為止！</color>然後變身展開第二場！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"으음…… 미리네 양은 화려한 액션 연출과 긴장감 있는 전투를 좋아하시는군요.","JPN":"うむ……マリ君は派手なアクション演出と緊張感のある戦闘が好きなんだね。","ENG":"Hmm... I see you’re very much into intense battles and flashy action, Rinae.","TWN":"嗯嗯……原來宓璃奈喜歡大動作刺激的戰鬥場面。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와! 제가 하고 싶은 말이 딱 그거예요! 쌤은 어떻게 그렇게 제 마음을 잘 아세요?","JPN":"うわ！　それです！　ウチが言いたかったこと！　先生はどうしてそんなにウチの心をよく知ってるんですか？","ENG":"Wow! That’s exactly what I wanted to say! You know me so well, Teach!","TWN":"哇！完全就是這個意思！老師你很懂我欸？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 그야 뭐 전 미리네 양의 선생님이니까요.","JPN":"はは、そりゃあ、私はマリ君の先生だからね。","ENG":"Ha ha, I am your teacher after all.","TWN":"哈哈，沒什麼啦，畢竟是我是你的老師嘛。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그러고보니, 미리네 누나는 선생님이랑 말할 때는 사투리를 안 쓰는구나.","JPN":"そういえば、マリさんって先生と話してる時には方言を使わないんだな。","ENG":"Come to think of it, Rinae doesn’t use her accent when she’s talking to her teacher.","TWN":"這麼說來，宓璃奈姊姊在和老師對話時，都不會唄來唄去的，也比較有禮貌。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"이상하네…… 혹시 보기보다 누나는 선생님을 어려워하는 건가?","JPN":"おかしいな……もしかして、マリさんって意外と先生のことが苦手なのかな？","ENG":"Strange... Does she feel uncomfortable around him?","TWN":"奇怪……還是其實她蠻怕老師的？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……그럼, 다음은 보라 양?","JPN":"……では、次はシホ君？","ENG":"...Well then, Bora. Would you like to be the second speaker?","TWN":"……那下一個換寶拉？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보라 양은 게임에서 어떤 부분이 가장 중요하다고 생각하시나요?","JPN":"シホ君はゲームでどういう部分が一番重要だと思うかな？","ENG":"Which part of a game would be most important to you?","TWN":"寶拉覺得一個遊戲最重要的是什麼？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……BGM이요.","JPN":"……BGMです。","ENG":"...The background music.","TWN":"……BGM。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이런 말도 있으니까……. 음악은…… 좋았다.","JPN":"こういう言葉もあるから……音楽は……よかった。","ENG":"You know what they say... \\"Despite everything... the music was okay\\".","TWN":"有句話說……音樂……很好。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"엥? 그거 별로 좋은 뜻 아닌데요.","JPN":"えっ？　それ、いい意味じゃないですよ。","ENG":"Eh? That’s not really a compliment.","TWN":"蛤？這不是誇獎的意思欸？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"어째서……? 좋다는 거잖아…… 음악이.","JPN":"どうして……？　いいってことでしょう……？　音楽が。","ENG":"Why...? It means good… the music is.","TWN":"怎麼會……？好不就是……好的意思？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그러니까 반대로 말하면 다른 건 다 안 좋았다는 뜻이잖아요.","JPN":"だから、逆に言うと他の要素はよくなかったって意味じゃないですか。","ENG":"Turn it the other way around. It means that the rest was bad.","TWN":"這個意思就是除了音樂之外都不好吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"좋던데…… 나는?","JPN":"よかったけど……私は。","ENG":"I... like it.","TWN":"不錯啊……我覺得？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 맞아요. 물론 게임에 있어서 BGM 역시 굉장히 중요한 부분이죠.","JPN":"はは、そうだね。もちろんゲームにおいてBGMもとても重要な部分だろう。","ENG":"Ha ha, you’re right. Music does contribute a lot to the overall gaming experience.","TWN":"哈哈，沒錯，在遊戲裡BGM也是很重要的元素。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"전부터 느꼈지만…… 여기 누나들은 다 특이한 것 같아.","JPN":"前から思ってたけど……ここの人たちってみんな変わってるよなぁ。","ENG":"I’ve noticed quite a lot of times... But these girls are all a little weird.","TWN":"我之前就這麼覺得……這群姊姊，好像都是怪咖。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아, 그렇지 다인 누나는 빼고!","JPN":"あ、タエさんは除いて！","ENG":"Oh right, except for Dain!","TWN":"喔，不對，不包括妲茵姊姊！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"다인 누나는 누구랑은 다르게 엄청 상냥하고 엄청 친절하거든. 헤헷.","JPN":"タエさんは誰かさんとは違ってとても優しくて、とても親切だし。へへっ。","ENG":"Dain is super sweet and kind, unlike someone. Heh.","TWN":"妲茵姊姊和其他人不一樣，她人美心善良，又很親切，呵呵。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……그럼, 다음은 다인 양?","JPN":"……では、次はタエ君？","ENG":"Now, next... Dain?","TWN":"……那，下一個換妲茵？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아! 저는 캐릭터 디자인이라고 생각해요, 선생님!","JPN":"あ！　私はキャラクターデザインだと思います、先生！","ENG":"Oh! I think it’s the character design, Teacher!","TWN":"喔！老師，我認為是角色設計！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"이거 봐, 누가 봐도 이게 가장 정상적인 대답이잖아.","JPN":"ほら、見てよ。この模範的な回答。","ENG":"See? That’s what a normal person would say!","TWN":"看吧，大家應該都同意這是最正常的答案吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"역시 다인 누나야! 연구회의 유일한 상식인! 하늘에서 내려온 천사야, 천사!","JPN":"やっぱりタエさんだ！　研究会唯一の常識人！　空から降りてきた天使だよ、天使！","ENG":"Dain, the only enlightened one in the group! She’s got to be an angel descended from the heavens!","TWN":"不愧是妲茵姊姊！研究社裡唯一的正常人！根本是天使下凡，是天使！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOG_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"특히 저는 몬스터 디자인이 가장 중요한 것 같아요. 예를 들면……","JPN":"特に私は、モンスターデザインが一番重要だと思うんです。例えば……","ENG":"To be more specific, I think monster designs are the most important. For instance...","TWN":"尤其是怪物的設計是最重要的，舉例來說……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"살갗을 찢어발기는 엄니를 가진 괴수나, 먹잇감의 뇌를 꿰뚫는 촉수를 가진 에일리언!","JPN":"肌を切り裂く牙を持った怪獣とか、獲物の脳を貫く触手を持ったエイリアン！","ENG":"Beasts with deadly fangs that tear flesh apart, or aliens with brain-piercing sharp tentacles!","TWN":"像是可以用大尖牙把皮膚扯爛的怪獸，或是可以用觸手穿過獵物腦袋的異形！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아! 그리고 요즘은 역관절이 좋더라고요! 너무너무 귀엽거든요!","JPN":"あ！　それに最近は逆関節にハマってるんです！　とってもかわいくて！","ENG":"Oh! I developed an interest in reversed joints recently! They’re soooo cute!","TWN":"還有！我最近愛上像貞子那種關節扭曲的怪物！超可愛的！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……엣!?","JPN":"……えっ！？","ENG":"...Eh?!","TWN":"……蛤！？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그러고보니 저번에는 다큐멘터리에서 레우코클로리디움 파라독섬이라는 아이를 봤는데, 이 아이의 기생 매커니즘은…….","JPN":"そういえばこの前ドキュメンタリーでロイコクロリディウムっていう子を見たんですけど、この子の寄生メカニズムは……","ENG":"I was watching a documentary the other night, and there was a parasite called Leucochloridium Paradoxum, and its parasitic mechanism is...","TWN":"說到這個，我之前有在紀錄片裡看到一種叫作彩幼吸蟲的寄生蟲……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하, 하하…… 그, 그렇군요.","JPN":"は、はは……そ、そうですか。","ENG":"H-ha ha... I-I see.","TWN":"哈，哈哈……好的…謝謝妲茵。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 박스 군? 박스 군의 의견을 말해볼까요?","JPN":"それでは、ダンボール君？　ダンボール君の意見を言ってみようか。","ENG":"Now, Box. What do you think?","TWN":"那紙箱小朋友呢？你要說說看你的意見嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"으음, 저는 플레이어들이 오랫동안 게임을 즐길 수 있는 방법을 고안해야 한다고 생각해요.","JPN":"うーん、僕はプレイヤーがゲームを長い間楽しめる方法を考えるべきだと思うんです。","ENG":"Mmm... I think we need to focus on providing a product that the players can enjoy for a long time.","TWN":"嗯嗯，我認為是要找出玩家可以持續在遊戲中得到樂趣的方法。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"다른 플레이어들과 경쟁하거나, 플레이어의 도전 욕구를 자극한다거나……","JPN":"他のプレイヤーと競争したり、プレイヤーの挑戦欲を刺激したり……","ENG":"Whether it be PvP, or motivating players with achievements...","TWN":"像是玩家間的競爭，或是激起玩家的挑戰慾望……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아니면 보물찾기처럼 게임 속에 이스터에그를 숨겨두는 것도 좋죠.","JPN":"宝探しみたいにゲームの中にイースター・エッグを隠しておくのもいいですね。","ENG":"Maybe even put in easter eggs like a treasure hunt.","TWN":"或是像尋寶一樣，在遊戲裡埋彩蛋也不錯。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"으음, 정석적이지만 좋은 의견이네요, 박스 군.","JPN":"うむ、定番だけどいい意見だね、ダンボール君。","ENG":"Hmm. A bit old school but a good answer. Well done, Box.","TWN":"嗯嗯～雖然有點老生常談，不過是很棒的意見喔。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"결국, 게임의 본질은 놀이.","JPN":"結局、ゲームの本質は遊び。","ENG":"Games, at their essence, are playing.","TWN":"遊戲的本質就是要有人玩！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사람이 뭘 원하고, 무엇에 즐거워하는지에 대한 통찰이 필요하죠.","JPN":"人が何を欲しがっていて、何を楽しいと思うかについて見抜くことが必要なんだ。","ENG":"It’s important for us to have insight on what the players want, and what they enjoy.","TWN":"必須觀察出玩家想要什麼、喜歡什麼。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보통 그런 통찰은 본인이 즐거웠던 경험을 돌이키는 과정에서 깨닫게 된답니다. 그렇다면…….","JPN":"そして、通常そういった見抜く力は、本人が楽しいと思った経験を振り返ることで気付くようになる。それなら……","ENG":"Usually, that kind of wisdom comes from looking back at our past precious experiences. And so...","TWN":"而這通常會在回想自己過去玩遊戲時的經驗中找到，既然如此……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"처음에는 쉽게 믿지 못했지만…… 이젠 알 것 같아.","JPN":"最初は簡単に信じられなかったけど……今はわかる気がする。","ENG":"I didn’t believe it at first... But now I’m sure.","TWN":"雖然一開始有點不敢置信……但我明白了！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"틀림없어. 저 사람은 스트리트 카운터의 진짜 제작자가 분명해!","JPN":"間違いない。あの人は、本当にストリート・カウンターの制作者なんだ！","ENG":"It’s true. This guy really is the creator of Street Counter!","TWN":"沒錯！那個人就是街頭制裁者真正的製作人！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"꿈에 그리던 분을 멘토로 두고 게임 제작을 배우게 되다니…… 헤헷, 미리네 누나 말처럼 나, 어쩌면 진짜 운이 좋은 걸지도 모르겠어!","JPN":"夢に描いた人に指導してもらいながらゲーム制作を教わることになるなんて……へへっ、マリさんも言ってたように、僕って本当についてるのかも！","ENG":"To have the idol of my dreams as my game development mentor... Heh. Maybe I do draw the best bull all the time, like Rinae says!","TWN":"竟然有機會拜夢想中的大人物為師，學習如何製作遊戲……呵呵，難道宓璃奈姊姊說的沒錯，我真的很幸運嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……그래서 오늘은 카운터즈 사가 프로젝트의 첫 날인만큼 우선 여러분과 즐거운 경험을 공유하는 자리를 마련해보았습니다.","JPN":"……というわけで、今日はカウンターズ・サーガプロジェクトの初日だし、まずみんなと楽しい経験を共有する場を用意してみたんだ。","ENG":"...Anyway, I've gathered you all here for the project launch of Counters Saga creating cherished memories with one another.","TWN":"……今天是制裁者傳奇企劃的第一天，我有為大家準備好一個可以共同創造美好經驗的機會。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아, 갑자기 기대된다!","JPN":"あ、急に楽しみになってきた！","ENG":"Oh, I’m so pumped up for this!","TWN":"哇，突然好期待喔！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"과연 전설적인 게임 제작자는 어떤 강연을 보여주실까?","JPN":"はたして伝説的なゲーム制作者はどんな話をしてくれるんだろう？","ENG":"I wonder what kind of things a legendary game developer talks about.","TWN":"究竟傳說中的遊戲製作人會帶來什麼精采的演說呢？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……바로 놀이공원이랍니다.","JPN":"……それは、遊園地です。","ENG":"...So, we're going to an amusement park.","TWN":"……就是，遊樂園。"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……엣!?","JPN":"……えっ！？","ENG":"...Huh?!","TWN":"……蛤！？"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"프리패스 입장권은 제가 미리 끊어 뒀습니다.","JPN":"フリーパスと入園券は私がもう購入しておいた。","ENG":"I already prepared tickets for us.","TWN":"我已經事先買好快速通關券，"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여러분은 오늘 하루 마음껏 즐기시기만 하면 되죠.","JPN":"みんなは今日一日、思う存分楽しんでくれればいい。","ENG":"Your job for today is to enjoy this day as much as possible.","TWN":"你們今天只要盡情玩就好！"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와아! 역시 쌤이 짱이에요! 쌤, 저랑 롤러 코스터 타러 가요!","JPN":"わあ！　やっぱ先生、最高！　先生、ウチとジェットコースター乗りに行きましょ！","ENG":"Wow! You’re the best, Teach! C'mon, let’s ride that roller coaster together!","TWN":"哇！老師好棒！老師，我們去搭雲霄飛車！"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"사주세요……. 솜사탕…… 아주 달달한.","JPN":"買ってください……綿あめ……とても甘い。","ENG":"Cotton candy… really sweet one… buy me.","TWN":"買給我……棉花糖……甜甜的。"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"잠깐만요!! 선생님!!","JPN":"待ってください！！　先生！！","ENG":"Wait! Teacher!","TWN":"先等一下！！老師！！"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"제작 기간 그렇게 넉넉하지 않은데, 첫날부터 이래도 되는 거예요?","JPN":"制作期間もそんな長くないのに、初日からこれで大丈夫なんですか？","ENG":"We’re not exactly on an easy schedule here. Are you sure we should be doing this on our first day?","TWN":"我們時間有限，第一天就這樣玩樂沒問題嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정하지 마세요. 게임 개발이라는 건 그렇게 만만하지 않거든요.","JPN":"心配しなくても大丈夫だよ。ゲーム開発というのは、そう簡単じゃないからな。","ENG":"Don’t worry. Game development isn’t all fun and games.","TWN":"放心啦，製作遊戲可沒那麼容易。"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오히려 이렇게 첫 날이 아니면 놀 기회가 별로 없을지도 모릅니다.","JPN":"むしろ、初日でないとこうやって遊ぶ機会がないかもしれないよ。","ENG":"And today might be your last chance to have some fun.","TWN":"就因為是第一天才有時間玩樂，之後可能會忙到連睡覺時間都沒有呢。"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"박스군도 이번에 미리네 양, 혹은 다른 누나들과 조금 친해져보는 건 어떨까요?","JPN":"ダンボール君もこの機会にマリ君や他の人たちと少し仲良くなってみるのはどうかな？","ENG":"Why don’t you get acquainted more with Rinae or the other girls, Box?","TWN":"紙箱小朋友，不如你就趁這個機會，和宓璃奈或其他姊姊拉近距離吧？"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아, 아니! 그래도……! 시간을 좀 더 생산적으로 쓰는 편이 좋지 않을까요?","JPN":"い、いや！　でも……！　時間をもっと効率良く使った方がいいんじゃないですか？","ENG":"B-but...! Don’t you think it’d be wiser to use our time doing something productive?","TWN":"可…可是……！不是應該更有效率地運用時間嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 박스 군은 성실하군요.","JPN":"はは、ダンボール君は真面目だね。","ENG":"Ha ha, you’re a hard worker, aren’t you?","TWN":"呵呵，你說話很直接呢。"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 기획이라는 건 책상에 앉아서만 하는 게 아닙니다.","JPN":"でも、企画というものは机の上でだけするものじゃないんだよ。","ENG":"Alas, game design isn’t always about sitting at a desk and thinking.","TWN":"不過所謂的企劃，不是紙上談兵，"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"일상 속에서 조금씩, 조금씩 힌트를 얻는거죠.","JPN":"日常の色んなところから少しずつヒントを得るものなんだ。","ENG":"It’s about getting inspired from our daily lives.","TWN":"而是要從日常生活中，一點一點得到靈感。"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사실, 박스 군이 좋아하는 샐러리맨X도 출근하는 회사원을 모티브 삼아 탄생했거든요.","JPN":"実際、ダンボール君が好きなサラリーマンXも出勤する会社員をモチーフにして誕生したんだからね。","ENG":"In fact, your favorite character, Salaryman X was created from businessmen going to work.","TWN":"其實你喜歡的上班族X，也是以通勤路上的上班族去做發想的。"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그, 그게 정말이에요!? 샐러리맨X에 그런 개발 비화가……","JPN":"そ、それは本当ですか！？　サラリーマンXにそんなビハインドストーリーが……","ENG":"R-really?! I had no idea there was such a backstory to his creation...","TWN":"真…真的嗎！？原來上班族X還有這樣的幕後故事……"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 물론이죠. 오늘은 박스 군도 어깨에 힘을 좀 빼고, 느긋하게 놀아보는 건 어떨까요?","JPN":"はは、もちろんだよ。今日はダンボール君も肩の力を抜いて、のんびり遊んでみてはどうかな。","ENG":"Ha ha, of course. So relax and loosen up a bit. Take it easy and enjoy the day.","TWN":"哈哈，當然。你今天就放輕鬆好好玩吧？"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러다보면, 문득 어떤 좋은 아이디어가 떠오를지도 모르니까요.","JPN":"そうしているうちに、ふと何かいいアイデアが浮かぶかもしれないよ。","ENG":"You never know what might spark your inner light bulb during the process.","TWN":"說不定會突然冒出很棒的點子喔？"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아하, 그런 거였구나! 알겠어요! 어떤 아이디어가 좋을 지 한 번 생각해 볼게요!","JPN":"ああ、なるほど！　わかりました！　どんなアイデアがいいか、一度考えてみますね！","ENG":"Aha, I see! Okay! I’ll try to come up with some good ideas!","TWN":"哈哈，原來是這樣！那好！我會好好尋找靈感的！"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"쌤, 쌤! 빨리요! 저희 롤러코스터 타러 가요!","JPN":"先生、先生！　早く！　ジェットコースター乗りに行きましょ！","ENG":"Teach, Teach! Hurry! Let’s go ride the roller coaster!","TWN":"老師！快點啦！我們去搭雲霄飛車！"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"먹고 싶어요…… 선생님……. 달콤한 솜사탕.","JPN":"食べたいです……先生……甘い綿あめ。","ENG":"Teacher… sweet cotton candy… I want.","TWN":"我想吃……老師……甜甜的棉花糖。"},"stage":{"bg":"PARK","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"으음, 좋았어! 선생님 말씀대로 생각해보는 거야!","JPN":"うーん、よっし！　先生の言うとおり、考えてみるぞ！","ENG":"Okay, good! I’ll get inspirations, just like Teacher told me to!","TWN":"嗯嗯，好吧！我會嘗試按照老師的話去思考！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"어디 보자…… 놀이공원에서 게임 컨텐츠로 쓸 만한 건…….","JPN":"えっと……遊園地でゲームコンテンツとして使えそうなものは……","ENG":"Let’s see... What could possibly be used for our game at an amusement park?","TWN":"我看看喔……遊樂園中適合拿來當作遊戲題材的是……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"멍! 멍멍!","JPN":"ワン！　ワンワン！","ENG":"Woof! Woof Woof!","TWN":"汪！汪汪！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_07"},{"id":"L24_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"귀여운 강아지?","JPN":"かわいい犬？","ENG":"A cute puppy?","TWN":"可愛狗狗？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"앗, 너는 켈베로스잖아? 그렇다는 말은…….","JPN":"あっ、ケルベロスか？　ってことは……","ENG":"Oh, it’s Cerberus! That means...!","TWN":"喔，你不是克爾柏洛斯嗎？意思是……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_02"},{"id":"L28_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와아, 박스 군 찾았다!","JPN":"わあ、ダンボール君、見つけた！","ENG":"Oh, Boxie! There you are.","TWN":"哇，我找到你了，紙箱小朋友！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"어? 다인 누나? 다른 누나들이랑 같이 가신 거 아니었어요?","JPN":"え？　タエさん？　他のみんなと一緒に行ったんじゃなかったんですか？","ENG":"Huh? Dain? I thought you were with the other girls.","TWN":"嗯？妲茵姊姊？你沒有和其他人一起去玩嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아아, 그게…… 나는 놀이기구는 어지러워서 잘 못 타거든.","JPN":"うん、それがね……私、乗り物は目まいがして苦手なの。","ENG":"Oh, that... I’m not really good with rides. I get nauseous easily.","TWN":"喔～因為……我不太能搭遊樂器材，會頭暈。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그보다 박스 군, 혹시 잠깐 시간 괜찮아?","JPN":"それよりダンボール君、ちょっといいかな？","ENG":"By the way, Boxie... Are you free right now?","TWN":"我來找你是想問，你有時間嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"나 사실 박스 군이랑 같이 가고 싶은 곳이 있는데…….","JPN":"私、実はダンボール君と一緒に行きたいところがあるんだけど……","ENG":"There’s this place I want to go with you...","TWN":"我想要找你跟我去一個地方……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네? 저랑요?","JPN":"え？　僕とですか？","ENG":"Huh? With me?","TWN":"什麼？找我一起？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응. 리네랑 보라는 <color=#ffd34c>그런 곳</color>을 별로 안 좋아해서…….","JPN":"うん。マリちゃんとシホちゃんは<color=#ffd34c>ああいうところ</color>があまり好きじゃないから……","ENG":"Yes. Rinae and Bora aren’t really keen on <color=#ffd34c>these kinds of places</color>...","TWN":"嗯，因為璃奈和寶拉不太喜歡<color=#ffd34c>那種地方</color>……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그, <color=#ffd34c>그런 곳</color>이라고 하면……?","JPN":"あ、<color=#ffd34c>ああいうところ</color>って……？","ENG":"W-what do you mean by <color=#ffd34c>these kinds of places</color>...?","TWN":"那…<color=#ffd34c>那種地方</color>是……？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};